HANDOFF_FRAMEBUFFER_HEIGHT_OFFSET = 16
HANDOFF_FRAMEBUFFER_HEIGHT_END = 24
HANDOFF_FRAMEBUFFER_PITCH_OFFSET = 24
HANDOFF_FRAMEBUFFER_PITCH_END = 32
HANDOFF_FRAMEBUFFER_BPP_OFFSET = 32
HANDOFF_FRAMEBUFFER_BPP_END = 34
HANDOFF_FRAMEBUFFER_MEMORY_MODEL_OFFSET = 34
HANDOFF_FRAMEBUFFER_MEMORY_MODEL_END = 35
HANDOFF_FRAMEBUFFER_RED_MASK_SIZE_OFFSET = 35
HANDOFF_FRAMEBUFFER_RED_MASK_SIZE_END = 36
HANDOFF_FRAMEBUFFER_RED_MASK_SHIFT_OFFSET = 36
HANDOFF_FRAMEBUFFER_RED_MASK_SHIFT_END = 37
HANDOFF_FRAMEBUFFER_GREEN_MASK_SIZE_OFFSET = 37
HANDOFF_FRAMEBUFFER_GREEN_MASK_SIZE_END = 38
HANDOFF_FRAMEBUFFER_GREEN_MASK_SHIFT_OFFSET = 38
HANDOFF_FRAMEBUFFER_GREEN_MASK_SHIFT_END = 39
HANDOFF_FRAMEBUFFER_BLUE_MASK_SIZE_OFFSET = 39
HANDOFF_FRAMEBUFFER_BLUE_MASK_SIZE_END = 40
HANDOFF_FRAMEBUFFER_BLUE_MASK_SHIFT_OFFSET = 40
HANDOFF_FRAMEBUFFER_BLUE_MASK_SHIFT_END = 41
HANDOFF_FRAMEBUFFER_RESERVED_OFFSET = 41
HANDOFF_FRAMEBUFFER_RESERVED_END = 46

def sha256(data: bytes) -> bytes:
    return hashlib.sha256(data).digest()


def generation_identity(data: bytes) -> bytes:
    return sha256(
        data[:GENERATION_HEADER_IDENTITY_OFFSET]
        + bytes(GENERATION_HEADER_IDENTITY_END - GENERATION_HEADER_IDENTITY_OFFSET)
        + data[GENERATION_HEADER_IDENTITY_END:]
    )


def bootstate_checksum(slot: bytes) -> bytes:
    return sha256(
        slot[:BOOTSTATE_CHECKSUM_OFFSET]
        + bytes(BOOTSTATE_CHECKSUM_END - BOOTSTATE_CHECKSUM_OFFSET)
        + slot[BOOTSTATE_CHECKSUM_END:]
    )


def bootstore_checksum(data: bytes) -> bytes:
    offset = BOOTSTORE_DIRECTORY_OFFSET + BOOTSTORE_HEADER_CHECKSUM_OFFSET
    end = BOOTSTORE_DIRECTORY_OFFSET + BOOTSTORE_HEADER_CHECKSUM_END
    return sha256(data[BOOTSTATE_SLOT_BYTES * BOOTSTATE_SLOT_COUNT : offset] + bytes(end - offset) + data[end:])
